import java.io.*;
import java.util.*;

class Solution {
    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        long total = 0;
        ArrayList<String> out = new ArrayList<>();
        while (sc.hasNextLong()) {
            total += sc.nextLong();
            out.add(Long.toString(total));
        }
        System.out.println(String.join(" ", out));
    }
}

